import { Lesson } from './types';
import { createLesson } from './data_helpers';

export const efLessonsB1: Lesson[] = [
  createLesson('g3-ef-b1-l1', 'L1: 3ª Série — Práticas Corporais e Projeto de Vida', 'educacao_fisica', 'A 3ª Série representa a síntese da jornada de Educação Física no Ensino Médio. Neste ano, aprofundaremos a análise crítica das práticas corporais, desenvolveremos projetos comunitários e prepararemos cada estudante para uma vida ativa e autônoma além da escola. Diagnóstico integrado: avaliação física completa (aeróbia, força, flexibilidade, velocidade, coordenação) e avaliação reflexiva (conhecimento sobre saúde, esporte e cultura corporal). Discussão: como a EF se conecta ao seu projeto de vida? Quais práticas corporais farão parte da sua vida adulta? A autonomia para gerenciar a própria saúde começa agora.', ['Como você pretende manter um estilo de vida ativo após o Ensino Médio? Quais recursos e estratégias você já tem?', 'Qual é a prática corporal que mais fez sentido para você ao longo do Ensino Médio? O que ela representa na sua vida?']),
  createLesson('g3-ef-b1-l2', 'L2: Práticas Corporais como Patrimônio Cultural', 'educacao_fisica', 'As práticas corporais são formas de expressão cultural que carregam a história dos povos. A BNCC (EM13LGG101) destaca a compreensão dos processos históricos e dos marcadores sociais nas práticas corporais. Evolução histórica: como o futebol mudou de esporte elitista britânico para esporte popular global; como a capoeira passou de luta proibida a patrimônio da humanidade; como o yoga chegou do misticismo hindu ao estúdio de academia contemporâneo. Marcadores sociais: classe, gênero, raça e regional como determinantes de quais práticas são acessíveis e valorizadas. No Tocantins: o cerrado como cenário de práticas únicas (corrida de tora, pesca artesanal, danças indígenas). Como preservar a diversidade corporal do nosso estado?', ['Escolha uma prática corporal e analise como ela foi transformada por contextos históricos e marcadores sociais ao longo do tempo.', 'Quais práticas corporais do Tocantins correm risco de desaparecer? O que pode ser feito para preservá-las?']),
  createLesson('g3-ef-b1-l3', 'L3: Esporte e Globalização — Identidade e Padronização', 'educacao_fisica', 'A globalização homogeneizou o esporte: as grandes ligas americanas (NFL, NBA, MLB) e europeias (UEFA Champions League, Premier League) dominam o imaginário esportivo global. Consequências: esportes tradicionais e locais perdem espaço; atletas migraram de países periféricos para ligas ricas (fuga de talentos); a lógica do mercado substituiu a lógica da cultura. Resistências: as Olimpíadas incluem esportes não anglófonos; os Jogos Mundiais dos Povos Indígenas; as ligas regionais brasileiras. No Tocantins: o futebol regional (Campeonato Tocantinense) vs. o futebol global da TV aberta. Identidade esportiva: ser torcedor do Palmas FC vs. ser torcedor do Manchester United — o que esses vínculos dizem sobre nossa identidade?', ['Como a globalização do esporte afeta a identidade esportiva regional e local? Você se identifica mais com esportes globais ou locais?', 'Por que grandes atletas brasileiros emigram para ligas europeias ou americanas? Quais são as consequências para o esporte brasileiro?']),
  createLesson('g3-ef-b1-l4', 'L4: Voleibol — Análise Tática Avançada e Arbitragem', 'educacao_fisica', 'Voleibol como estudo de caso de excelência brasileira. Análise tática avançada: o sistema 5-1 em profundidade — posição do levantador em cada rotação, cobertura de ataque, defesa de cortada, organização do bloqueio duplo e triplo. Leitura de jogo: como identificar o "setter dump" (fintar de levantador), o ataque por trás (pipe), o ataque de ponta (bola 1). Estatística no voleibol moderno: pontos de ataque, porcentagem de recepção positiva, bloqueios. Arbitragem: sinais do árbitro, regras de contato, let no saque, regra de pé sob a rede. O sistema de pontos por rally point (desde 1999): como mudou o jogo. Prática: jogo com ênfase em análise tática em tempo real.', ['Explique o sistema 5-1 no voleibol: como funciona a posição do levantador em cada rotação e qual é a vantagem desse sistema?', 'Quais são os principais sinais de árbitro no voleibol e o que cada um significa? Por que conhecer as regras é importante para todos os jogadores?']),
  createLesson('g3-ef-b1-l5', 'L5: Atletismo — Provas de Resistência e Fisiologia', 'educacao_fisica', 'O atletismo de resistência é o teste máximo da fisiologia humana. Provas: 800m, 1500m, 5000m, 10.000m, maratona (42,195 km). Recordes mundiais: Eliud Kipchoge (Quênia) — maratona em 2h00min35s (Berlim 2023), quebrando a barreira dos 2 horas. A lógica do treinamento de resistência: zonas de intensidade (zona 1 a zona 5), limiar anaeróbio, EPOC (excesso de consumo de oxigênio pós-exercício). Periodização: macro, meso e microciclos de treinamento. Por que africanos dominam o atletismo de resistência? Debate: altitude, cultura de corrida desde a infância, biomecânica ou simplesmente acesso? No Tocantins: corrida de rua de Palmas (Maratona Orla, provas de rua em Araguaína). Projeto: planejamento de uma prova de 3 km para a escola.', ['O que é o limiar anaeróbio e por que ele é a variável mais importante no treinamento de corredores de média e longa distância?', 'Por que atletas quenianos e etíopes dominam as provas de resistência no atletismo mundial? Quais são as teorias que explicam essa supremacia?']),
  createLesson('g3-ef-b1-l6', 'L6: Basquetebol — NBA e o Impacto Cultural', 'educacao_fisica', 'A NBA transformou o basquete em fenômeno cultural global. História: criada em 1946, tornou-se a maior liga esportiva do mundo com Michael Jordan (Dream Team, 1992). O impacto cultural da NBA: Michael Jordan e a globalização do tênis (Air Jordan — Nike vendeu US$162 milhões em 1984), o "Showtime" dos Lakers, LeBron James como ativista. A revolução dos 3 pontos: de 1979 à explosão de Stephen Curry (402 arremessos de 3 por temporada em 2015-16). Brasil na NBA: Leandro Barbosa, Bruno Caboclo, Raul Neto, Gui Santos (atual). O basquete periférico no Brasil: a rua, os projetos sociais, o caminho para a NBA. Prática: exercício de arremesso de 3 pontos com análise estatística (porcentagem de acerto).', ['Como a NBA influenciou a cultura global além do esporte? Dê exemplos de impacto na moda, música e ativismo político.', 'O que é o "pace and space" (ritmo e espaço) na filosofia moderna de jogo da NBA? Por que essa tendência revolucionou o basquete?']),
  createLesson('g3-ef-b1-l7', 'L7: Ginástica Acrobática e Esportes Artísticos', 'educacao_fisica', 'A ginástica acrobática é praticada em duplas, trios ou quartetos com elementos de força, equilíbrio, flexibilidade e acrobacia. Diferente da ginástica artística (competição individual em aparelhos), a acrobática tem como base a interação entre corpos. Elementos: pirâmides, lançamentos, portor, volante. A ginástica como arte: a fronteira com o circo, a dança e o teatro físico. No Brasil: o circo social como herdeiro da ginástica acrobática nas periferias. Parkour: a arte do deslocamento urbano — superar obstáculos urbanos com o próprio corpo, criado por David Belle na França nos anos 1990; olímpico a partir de Los Angeles 2028. Breakdance: foi olímpico em Paris 2024, retirado de LA 2028. Por que o COI inclui e retira esportes das Olimpíadas? Prática: pirâmides humanas em grupos de 4, com segurança e progressão.', ['O que é o parkour e quais habilidades físicas e mentais ele desenvolve? Por que ele está sendo considerado como modalidade olímpica?', 'O breakdance foi olímpico em Paris 2024 mas foi excluído de LA 2028. Quais critérios o COI usa para incluir e retirar esportes das Olimpíadas?']),
  createLesson('g3-ef-b1-l8', 'L8: Capoeira — Mestres e Resistência', 'educacao_fisica', 'Aprofundamento histórico e filosófico da capoeira. A repressão histórica: a capoeira foi criminalizada no Código Penal de 1890 (artigo 402); praticada nas sombras até a legalização com Getúlio Vargas em 1930, quando Mestre Bimba criou a Capoeira Regional legitimada. Mestres históricos: Mestre Bimba (1900-1974) — criador da Regional, lutou para que o Brasil reconhecesse a capoeira; Mestre Pastinha (1889-1981) — guardião da Angola, viveu e morreu na pobreza. A memória e a transmissão: como a capoeira se manteve viva através da oralidade, da música e do jogo? O berimbau como instrumento de comunicação: os toques narram o jogo. A capoeira como resistência política: do quilombo à academia. Grupos de capoeira em Palmas e no Tocantins. Prática: roda de capoeira — jogo angola e regional.', ['Como a criminalização e depois a legalização da capoeira refletem a história das relações raciais no Brasil?', 'Qual foi o papel dos Mestres Bimba e Pastinha para a preservação e legitimação da capoeira? Por que suas trajetórias de vida são tão diferentes?']),
  createLesson('g3-ef-b1-l9', 'L9: Corpo e Arte — Performances e Instalações', 'educacao_fisica', 'A body art (arte do corpo) usa o próprio corpo humano como material artístico e espaço de expressão. Artistas: Marina Abramović — a avó da performance art; ela suportou dor, exaustão e vulnerabilidade em peças de horas ou dias; "The Artist is Present" (2010, MoMA). Yoko Ono — "Cut Piece" (1964), sobre violência e passividade. No Brasil: Lygia Clark e o "Bicho" (objetos para manipulação corporal como arte participativa). Dança-teatro: Pina Bausch; sua companhia (Tanztheater Wuppertal) reconstruiu as dores humanas com o corpo. Como essas manifestações dialogam com a Educação Física? O corpo não é apenas atlético — é também poético, político e crítico. Projeto: criar uma performance de 2-3 minutos em grupo que use o corpo para comunicar uma ideia social.', ['O que a body art e a performance art revelam sobre o corpo humano além de suas capacidades físicas?', 'Crie um conceito para uma performance corporal em grupo: qual mensagem você quer transmitir? Quais movimentos e elementos você usaria?']),
  createLesson('g3-ef-b1-l10', 'L10: Esporte Olímpico — Los Angeles 2028 e Brasil', 'educacao_fisica', 'Los Angeles receberá os Jogos Olímpicos de 2028 — a primeira vez que os EUA recebem desde Atlanta 1996. Novos esportes confirmados: flag football (versão sem contato do futebol americano — 6 times por gênero), críquete (retorna após 128 anos), squash (aguardado por décadas), baseball/softball (retorna), lacrosse. Retirados: breakdancing. Por que os EUA escolhem esses esportes para 2028? A influência política do país sede na composição do programa olímpico. Brasil em Los Angeles 2028: quais são as apostas de medalha? Reconstrução pós-Paris 2024 — que modalidades têm maior potencial? Tocantins no esporte olímpico: atletas tocantinenses em Olimpíadas (pesquisa coletiva). A importância dos Jogos para o esporte universitário americano.', ['Por que o país sede tem influência sobre quais esportes são incluídos nas Olimpíadas? Quais interesses políticos e econômicos estão envolvidos?', 'Pesquise: algum atleta nascido no Tocantins ou que tenha passado pelo estado já participou de Jogos Olímpicos? Conte a história.']),
  createLesson('g3-ef-b1-l11', 'L11: Saúde do Adolescente — Riscos e Proteções', 'educacao_fisica', 'A adolescência é um período de vulnerabilidade e de construção. Riscos à saúde do adolescente: uso de álcool e drogas (início precoce aumenta risco de dependência em 3-5x); sedentarismo crescente (>60% dos adolescentes brasileiros são insuficientemente ativos); transtornos alimentares (anorexia e bulimia cresceram 40% entre 2020-2023 no Brasil); violência (jovens de 15-29 anos são os principais alvos de homicídio no Brasil); IST (Infecções Sexualmente Transmissíveis — uso de preservativo caiu entre adolescentes). Fatores de proteção: prática esportiva regular, vínculo familiar, escola de qualidade, projetos de vida, comunidade de pertencimento. A atividade física como fator de proteção: como o esporte reduz a exposição a riscos.', ['Quais são os principais fatores de risco e de proteção para a saúde do adolescente brasileiro? Como a atividade física atua como fator protetor?', 'Como o início precoce do uso de álcool e outras drogas afeta o desenvolvimento cerebral dos adolescentes? Qual é a relação com a prática esportiva?']),
  createLesson('g3-ef-b1-l12', 'L12: Danças do Mundo — Globais e Locais', 'educacao_fisica', 'O mundo dança — e cada dança conta a história de um povo. Danças globais: k-pop (Coreia do Sul — BTS, Blackpink; coreografias altamente técnicas e sincronizadas), bollywood (Índia — dança-teatro com influência do folclore e do cinema), flamenco (Espanha — expressão da paixão e da dor através dos pés e mãos), tango (Argentina/Uruguai — dança de resistência e sensualidade). Danças afro-diaspóricas: samba, cumbia, son cubano, calipso — todas com raízes na diáspora africana, contando histórias de resistência. No Tocantins: a mistura de ritmos nordestinos (forró, baião), caipiras (cururu, catira) e indígenas que formam a identidade dançante tocantinense. O k-pop como fenômeno jovem global: o que sua popularidade diz sobre identidade e globalização? Prática: aprender passos básicos de k-pop e de forró — dança como conexão intercultural.', ['Por que as danças afro-diaspóricas (samba, cumbia, calipso) compartilham características similares mesmo em países e culturas diferentes?', 'O k-pop é considerado "imperialismo cultural" por alguns e "globalização legítima" por outros. Qual é o seu ponto de vista? Justifique.']),
  createLesson('g3-ef-b1-l13', 'L13: Avaliação Física 1 — Linha de Base do Ano', 'educacao_fisica', 'Primeira avaliação física do ano — estabelecendo a linha de base para acompanhamento ao longo de 2026. Bateria completa: (1) Teste de Cooper (12 min de corrida — resistência aeróbia); (2) Flexão de braço em 1 min (força-resistência de membros superiores); (3) Abdominal em 1 min (força-resistência do core); (4) Sentar-e-alcançar (flexibilidade de cadeia posterior); (5) Sprint de 40m (velocidade de aceleração); (6) Salto vertical (força explosiva de membros inferiores). Análise estatística da turma: média, maior valor, menor valor por teste. Comparação com as referências da PROESP-BR (Projeto Esporte Brasil) para a faixa etária. Estabelecimento de metas: cada aluno define seus objetivos para a avaliação final (4º bimestre).', ['Comparando seus resultados com as referências da PROESP-BR, como você avalia sua aptidão física atual? Em qual capacidade você mais quer melhorar?', 'Estabeleça uma meta realista e mensurável para cada um dos 6 testes até o final do ano. O que você vai fazer para alcançá-las?']),
  createLesson('g3-ef-b1-l14', 'L14: Esportes de Luta — MMA, Boxe e Ética', 'educacao_fisica', 'Os esportes de combate geram fascínio e controvérsia. O MMA (Artes Marciais Mistas) é o esporte de mais rápido crescimento no mundo (UFC é a maior organização, criada em 1993). Brasil tem a maior delegação de campeões do UFC fora dos EUA: Anderson Silva, José Aldo, Amanda Nunes, Charles Oliveira, Poatan. Boxe olímpico: regras diferentes do profissional (capacete, mais rounds curtos, pontuação por técnica). Questões éticas: lesão cerebral (CTE — Encefalopatia Traumática Crônica) em esportes de contato. Por que atletas aceitam esses riscos? O debate sobre a regulamentação do MMA entre adolescentes. Lutas e masculinidade: como esportes de combate reforçam ou desconstroem estereótipos. Capoeira como luta: recuperando a dimensão marcial da prática. Prática: defesa pessoal básica sem contato (esquiva, bloqueio).', ['Qual é a diferença entre a violência de um esporte de combate e a violência cotidiana? O que torna o combate esportivo eticamente aceitável?', 'Como os esportes de luta podem contribuir para a formação do caráter e a disciplina dos jovens? Quais são os riscos que precisam ser gerenciados?']),
  createLesson('g3-ef-b1-l15', 'L15: Fisiologia Aplicada — Metabolismo e Composição Corporal', 'educacao_fisica', 'Aprofundamento em fisiologia do exercício para a 3ª Série. Metabolismo energético em detalhe: sistema fosfagênio (ATP-CP — atividades de 0-10 segundos, como 100m rasos); sistema glicolítico (glicose → lactato — atividades de 30 segundos a 2 minutos, como 400m); sistema oxidativo (gorduras + glicose + oxigênio — atividades de mais de 2 minutos, como maratona). O que determina qual sistema é mais utilizado: intensidade e duração do exercício. Composição corporal avançada: índice de adiposidade visceral (gordura que circunda órgãos internos — mais perigosa que a subcutânea); método de dobras cutâneas; bioimpedância tetrapolar. Termogênese: como o exercício aumenta o gasto calórico em repouso (EPOC). A dieta do atleta: carboidrato, proteína e gordura na proporção certa para cada tipo de esforço.', ['Explique os 3 sistemas energéticos. Em quais esportes cada sistema predomina? O que determina qual sistema é ativado?', 'Qual é a diferença entre gordura visceral e subcutânea? Por que a gordura visceral é mais preocupante para a saúde?']),
  createLesson('g3-ef-b1-l16', 'L16: Esporte no Tocantins — História e Patrimônio', 'educacao_fisica', 'O esporte no Tocantins tem história relativamente recente (estado criado em 1988), mas rica identidade. História do esporte tocantinense: futebol como principal modalidade (Palmas FC, Araguaína FC, Rio Negro AC); o atletismo com forte influência das comunidades indígenas; a pesca esportiva no Araguaia e no Tocantins; as corridas de tora do povo Krahô; as regatas no lago da UHE Lajeado. Grandes eventos: Campeonato Tocantinense de Futebol; corridas de rua em Palmas, Araguaína e Gurupi; Jogos Indígenas regionais; regata do Rio Tocantins. Gestão do esporte: SEEL (Secretaria de Estado da Juventude, Esporte e Lazer); prefeituras municipais; confederações regionais. Pesquisa: quais são os melhores atletas que o Tocantins já produziu?', ['Quais são os principais esportes praticados no Tocantins e como eles refletem a identidade cultural do estado?', 'Pesquise e apresente a história de um atleta tocantinense que tenha se destacado no esporte regional ou nacional. O que sua trajetória revela sobre as oportunidades esportivas no estado?']),
  createLesson('g3-ef-b1-l17', 'L17: Planejamento do Projeto Comunitário', 'educacao_fisica', 'O projeto comunitário de Educação Física é a atividade central da 3ª Série. Proposta: cada grupo (4-5 alunos) vai planejar e executar uma intervenção de prática corporal em um espaço da comunidade de Palmas (escola, bairro, praça, parque). Etapas do projeto: (1) Diagnóstico — qual é a demanda de prática física nesse espaço/público? (2) Planejamento — qual prática? Para quem? Como? Com que frequência? (3) Execução — mínimo de 2 sessões com pelo menos 10 participantes externos à turma; (4) Avaliação — o que funcionou? O que não funcionou? (5) Documentação — relatório com fotos e depoimentos dos participantes. O projeto será apresentado no 4º bimestre. Início: cada grupo define seu público-alvo e contexto.', ['Por que é importante que estudantes de EF realizem intervenções reais na comunidade, e não apenas na escola? O que essa experiência ensina?', 'Qual público-alvo e contexto seu grupo escolheu para o projeto comunitário? Quais são os desafios que vocês antecipam?']),
  createLesson('g3-ef-b1-l18', 'L18: Revisão do 1º Bimestre — Síntese Reflexiva', 'educacao_fisica', 'Revisão e síntese do 1º bimestre da 3ª Série. Temas abordados: práticas corporais como patrimônio cultural, esporte e globalização, voleibol tático, atletismo de resistência, basquete e impacto cultural, ginástica acrobática, capoeira histórica, corpo e arte, Olimpíadas 2028, saúde do adolescente, danças globais, avaliação física, lutas e ética, fisiologia aplicada, esporte tocantinense, planejamento do projeto comunitário. Avaliação: portfólio de reflexões — cada aluno seleciona 3 temas do bimestre e escreve 1 parágrafo de análise crítica sobre cada um, conectando-o à sua própria vida e ao contexto social. Discussão em círculo: qual tema gerou mais debate? O que foi mais surpreendente?', ['Dos temas do 1º bimestre, qual mais desafiou suas concepções prévias sobre esporte e corpo? Por quê?', 'Como você conecta os temas estudados em EF com outras disciplinas do currículo (sociologia, filosofia, biologia, história)?']),
];

export const efLessonsB2: Lesson[] = [
  createLesson('g3-ef-b2-l1', 'L1: Análise Crítica das Práticas Corporais na Mídia', 'educacao_fisica', 'A mídia molda a percepção que temos do esporte e do corpo. Análise crítica (BNCC EM13LGG101): como o esporte é representado em diferentes mídias — TV, redes sociais, publicidade, jornais. O discurso midiático sobre o corpo: ideal de corpo atlético impossível; antes-e-depois de academia como violência simbólica; a objetificação do corpo feminino no esporte (câmera que segue as atletas diferentemente dos atletas). Propaganda esportiva: como empresas como Nike ("Just Do It"), Adidas, Gatorade criam narrativas de superação para vender produtos. Esporte eletrônico (e-sports) na mídia: transmissões ao vivo no Twitch, cobertura do Campeonato Mundial de Free Fire (Brasil como 2º maior mercado). Exercício prático: analisar 3 peças de mídia esportiva identificando discurso, valores promovidos e interesses econômicos.', ['Quais são os valores que a publicidade esportiva (Nike, Adidas) promove? Eles são positivos ou há problemas a considerar?', 'Compare a cobertura midiática de uma competição masculina e uma feminina no mesmo esporte. O que as diferenças revelam sobre os valores da sociedade?']),
  createLesson('g3-ef-b2-l2', 'L2: Tênis — Grand Slams e História', 'educacao_fisica', 'O tênis é um dos esportes mais globais e socialmente seletivos. Os 4 Grand Slams: Australian Open (janeiro, Melbourne — piso duro), Roland Garros (maio/junho, Paris — saibro), Wimbledon (junho/julho, Londres — grama), US Open (agosto/setembro, Nova York — piso duro). As superfícies e seus estilos: o saibro favorece defesa e trocas longas; a grama favorece serviços e volleys; o piso duro equilibra os dois. Rafael Nadal e o saibro: 14 títulos em Roland Garros, o maior recordista de um único Grand Slam. Serena Williams: 23 Grand Slams, a maior de todos os tempos. Carlos Alcaraz (Espanha, 21 anos) como a nova geração. Tênis no Brasil: Gustavo Kuerten (Guga) — 3 Roland Garros, transformou o tênis em Brasil. A elitização do tênis: clubes privados, acesso restrito — como democratizar? Prática: noções básicas de forehand e backhand.', ['Por que Rafael Nadal dominou Roland Garros por tanto tempo? Como a especificidade do saibro explica esse domínio?', 'Como o tênis pode se tornar mais acessível a crianças de escolas públicas no Brasil? Quais iniciativas já existem?']),
  createLesson('g3-ef-b2-l3', 'L3: Judô Avançado — Competição e Pedagogia', 'educacao_fisica', 'Judô como estudo de caso de um esporte que preservou seus valores educativos no alto rendimento. Competição olímpica: categorias por peso (60 kg, 66 kg, 73 kg, 81 kg, 90 kg, 100 kg, +100 kg para homens); pontuação (ippon, waza-ari, shido); arbitragem no tatame e fora (câmera). O judô brasileiro nos Jogos de Paris 2024: Beatriz Souza (ouro, +78 kg), Daniel Cargnin, Rafael Macedo, Willian Lima — 1 ouro e mais medalhas. O judô como pedagogia: como o IJF (Federação Internacional de Judô) expandiu o programa "Judô for Peace" para zonas de conflito (refugiados, África, Oriente Médio). O papel do professor de judô: mais que técnico, é educador de caráter. Judô adaptado para pessoas com deficiência visual (Judô Paralímpico). Prática: ne-waza (técnicas no solo) — chave de braço e estrangulamento básico (com supervisão).', ['Como o judô preservou seus valores educativos (respeito, disciplina, ética) mesmo após tornar-se esporte olímpico profissional?', 'O que é o programa "Judô for Peace" e como ele usa o esporte como instrumento de paz em zonas de conflito?']),
  createLesson('g3-ef-b2-l4', 'L4: Futebol Feminino — Trajetória e Futuro', 'educacao_fisica', 'O futebol feminino é o esporte que mais cresce no mundo. A história da proibição: o decreto 3.199 de 1941 (governo Vargas) proibiu mulheres de praticarem futebol por "não condizer com as condições femininas"; a proibição durou até 1979. O renascimento: Marta (eleita 6 vezes melhor jogadora do mundo pela FIFA — mais do que qualquer homem) como símbolo. A Copa do Mundo Feminina de 2023 (Austrália/Nova Zelândia) transformou a modalidade: 2 bilhões de espectadores globais, estádios lotados. No Brasil: CBF ainda trata o futebol feminino com recursos desiguais (escândalo do uniforme em 2023 — CBF enviou uniformes sem adaptação para corpos femininos). Liga Brasileira Feminina: profissionalização crescente. O que o futuro do futebol feminino reserva?', ['Por que a proibição do futebol feminino no Brasil de 1941 a 1979 representa uma forma de violência de gênero?', 'O que o sucesso da Copa do Mundo Feminina de 2023 revela sobre a transformação da aceitação do futebol feminino pelo público global?']),
  createLesson('g3-ef-b2-l5', 'L5: Atividade Física e Longevidade — O que a Ciência Diz', 'educacao_fisica', 'A longevidade saudável é um dos maiores objetivos da humanidade. O estudo de "Blue Zones" (zonas azuis) identificou 5 regiões com maior concentração de centenários: Sardenha (Itália), Okinawa (Japão), Loma Linda (EUA), Nicoya (Costa Rica), Ikaria (Grécia). Características comuns: movimento natural ao longo do dia (não exercício intenso, mas caminhada e trabalho manual), propósito de vida, gestão do estresse, comunidade social, alimentação à base de plantas. No Japão, o conceito de "ikigai" (razão de viver) é atribuído à longevidade de Okinawa. Exercício vs. movimento: diferença entre treinar 1h/dia e ser sedentário 23h vs. mover-se com frequência ao longo do dia (NEAT — Non-Exercise Activity Thermogenesis). Para o nosso contexto: como incorporar mais movimento natural na rotina escolar e pós-escolar?', ['O que as "zonas azuis" têm em comum? Por que a atividade física das pessoas que vivem mais não é a academia convencional?', 'Como o conceito japonês de "ikigai" (razão de viver) se relaciona com a saúde e a longevidade? Você tem um ikigai? O que é?']),
  createLesson('g3-ef-b2-l6', 'L6: Esportes de Precisão — Tiro ao Alvo, Bocha e Esgrima', 'educacao_fisica', 'Os esportes de precisão exigem controle mental e motor fino. Tiro esportivo: olímpico desde 1896; subdivide-se em pistola, espingarda, shotgun; o foco mental (Zen e o tiro ao alvo — Philip Herrigel); controverso (uso de arma real). Bocha: tradicional europeia; bocce italiano, pétanque francês (muito popular na França); boccia paralímpica (para cadeirantes e pessoas com paralisia cerebral) — esporte de alto controle motor. Esgrima: um dos 5 esportes presentes em todas as Olimpíadas modernas (1896-); três armas (florete, sabre, espada) com regras distintas; vestimenta branca, máscara, luva. Por que esportes de precisão desenvolvem concentração, paciência, controle emocional e auto-regulação? Relação com meditação: estado de "flow" (Csíkszentmihályi) — concentração máxima sem esforço consciente.', ['O que caracteriza um esporte de precisão? Quais habilidades mentais esses esportes desenvolvem e como elas se transferem para outras áreas da vida?', 'O que é o estado de "flow" descrito por Csíkszentmihályi? Você já experimentou algo semelhante na prática de alguma atividade física?']),
  createLesson('g3-ef-b2-l7', 'L7: Nutrição Avançada — Suplementação e Mitos', 'educacao_fisica', 'A indústria de suplementação movimenta bilhões e promove muito mais marketing do que evidência científica. Suplementos com evidência sólida: (1) Creatina monohidratada — aumenta força e potência em 5-15% em exercícios de alta intensidade; segura e eficaz; (2) Proteína em pó (whey, caseína, proteína vegetal) — prática, não mágica — equivale a qualquer fonte proteica de qualidade; (3) Cafeína — melhora desempenho aeróbio e de curta duração em até 3-7%; (4) Beta-alanina — reduz fadiga em exercícios de 1-4 min. Mitos (sem evidência): fat burners, BCAA isolado (desnecessário com ingestão proteica adequada), pré-treinos "termogênicos" (majoritariamente marketing). O mercado de suplementos no Brasil: US$3 bilhões/ano. Para adolescentes: alimentação de qualidade substitui qualquer suplemento. Consulta a nutricionista esportivo é fundamental antes de qualquer suplementação.', ['Quais são os suplementos com evidência científica sólida e qual é o mecanismo de ação de cada um?', 'Por que a maioria dos suplementos vendidos nas academias não tem evidência científica? Como identificar o que é marketing e o que é ciência?']),
  createLesson('g3-ef-b2-l8', 'L8: Esporte e Direito — Estatuto do Torcedor e Legislação', 'educacao_fisica', 'O esporte tem um arcabouço jurídico amplo. Lei Pelé (Lei 9.615/1998): regulamenta o esporte profissional, os direitos de transmissão, o passe livre do atleta (antes, clubes "possuíam" jogadores indefinidamente). Estatuto do Torcedor (Lei 10.671/2003): garante ao torcedor a qualidade do espetáculo, a segurança nos estádios, a punição por violência. Lei Geral do Esporte (Lei 14.597/2023): nova legislação que moderniza o marco legal do esporte brasileiro. Tribunal Arbitral do Esporte (TAS/CAS em Lausanne): órgão internacional que julga disputas esportivas. Casos famosos: suspensão de atletas por doping (Tirunesh Dibaba, Lance Armstrong), disputas de contratos (Neymar e PSG). Direitos do atleta: contrato, imagem, saúde, férias. O que acontece quando um clube não paga o salário?', ['Quais foram as principais mudanças que a Lei Pelé trouxe para o futebol profissional brasileiro? O que era o "passe" e por que sua extinção foi importante?', 'Quais são os direitos garantidos ao torcedor pelo Estatuto do Torcedor? Você já viu esses direitos serem violados? Descreva um caso.']),
  createLesson('g3-ef-b2-l9', 'L9: Triatlo e Esportes Multidisciplinares', 'educacao_fisica', 'O triatlo (natação + ciclismo + corrida) é o teste mais completo de resistência e versatilidade. Distâncias: Sprint (750m/20km/5km), Olímpico (1,5km/40km/10km), Ironman (3,8km/180km/42km). O Ironman é considerado uma das provas mais duras do mundo — poucos acabam em menos de 9 horas. Triatletas como modelos de versatilidade: capacidade aeróbia excepcional, técnica de natação, potência no ciclismo, resistência na corrida. No Brasil: Alexandre Pires e Reinaldo Colucci como pioneiros. Pentratlo Moderno: natação, esgrima, equitação, tiro com laser e corrida-cross (olímpico desde 1912). Cross-Fit: metodologia de treinamento que combina força, condicionamento e habilidades olímpicas — comunidade intensa, debates sobre segurança. Duatlo, aquatlo, ciclotriatleta — variações para contextos sem mar ou natação.', ['Por que o triatlo é considerado um dos esportes mais completos do ponto de vista fisiológico? Quais capacidades físicas são exigidas?', 'O CrossFit tem defensores apaixonados e críticos veementes. Quais são os argumentos de cada lado? Com quem você concorda?']),
  createLesson('g3-ef-b2-l10', 'L10: Execução do Projeto Comunitário — 1ª Sessão', 'educacao_fisica', 'Primeira sessão de execução do Projeto Comunitário de EF. Os grupos saem a campo para realizar a intervenção planejada no 1º bimestre. Antes de cada sessão: checklist de segurança, confirmação de participantes, materiais. Durante a sessão: aplicar o planejamento com flexibilidade (adaptar se necessário), observar o engajamento dos participantes, registrar em fotos/vídeos (com autorização). Após a sessão: registro em diário de campo — o que funcionou? O que surpreendeu? O que será ajustado? A segunda sessão será no 3º bimestre. Reflexão coletiva em sala: compartilhar experiências da 1ª sessão — dificuldades encontradas e soluções adotadas.', ['Descreva como foi a 1ª sessão do seu projeto comunitário: o que funcionou, o que precisou de ajuste e o que os participantes disseram.', 'Quais foram as maiores dificuldades na execução da sessão? Como você as superou? O que vai mudar na próxima sessão?']),
  createLesson('g3-ef-b2-l11', 'L11: Psicologia Esportiva Avançada — Flow e Visualização', 'educacao_fisica', 'A psicologia esportiva é a ciência da performance mental. Estado de flow (Csíkszentmihályi): experiência de concentração total, prazer e eficiência máxima; 9 componentes (equilíbrio desafio-habilidade, objetivos claros, feedback imediato, perda da autoconsciência, transformação do tempo). Como induzir o flow: desafio levemente acima da habilidade atual, ambiente sem distração, rotinas pré-performance. Visualização mental: técnica usada por todos os atletas olímpicos; o cérebro não diferencia completamente experiência real de experiência imaginada (neuroplasticidade); Serena Williams visualizava cada ponto antes de servir. Rotina pré-competitiva: o papel dos rituais (Nadal ajustando as garrafas, Michael Jordan vestindo sempre as calções do North Carolina sob o uniforme dos Bulls). Zona de conforto vs. zona de crescimento: só cresce quem se desafia.', ['Quais são os 9 componentes do estado de flow identificados por Csíkszentmihályi? Como eles se manifestam em uma atividade esportiva?', 'Como a visualização mental funciona do ponto de vista neurocientífico? Como você poderia usar essa técnica para melhorar uma habilidade esportiva específica?']),
  createLesson('g3-ef-b2-l12', 'L12: Handebol — Seleção Brasileira e Táticas', 'educacao_fisica', 'O handebol brasileiro tem crescido tanto no masculino quanto no feminino. A seleção feminina: Eduarda "Duda" Amorim é considerada uma das melhores do mundo; Pan-americanas múltiplas. Sistema tático avançado: o arremesso de sete metros (penalidade): goleiro tenta adivinhar o canto; o gol de dois pontos (novidade — desde 2023, goleiro pode marcar); sistema ofensivo fast break; o bloqueio em ataque. A evolução do handebol: esporte criado em 1917 na Dinamarca; primeira Copa do Mundo em 1938; olímpico masculino desde 1972, feminino desde 1976. Pontos de destaque técnico: o pivô como referência ofensiva (atua costas para o gol), a armação de jogadas com a bola correndo entre os jogadores. Prática: simulação de situações de ataque com pivô.', ['Como funciona o novo gol de dois pontos no handebol (introduzido em 2023)? Que impacto essa regra traz para a dinâmica do jogo?', 'Descreva a função do pivô no handebol e quais habilidades técnicas e táticas essa posição exige.']),
  createLesson('g3-ef-b2-l13', 'L13: Ginástica Aeróbica e Step', 'educacao_fisica', 'A ginástica aeróbica surgiu nos anos 1970 com Jane Fonda e Kenneth Cooper (autor de "Aerobics", 1968). Evolução: Jane Fonda VHS (1982) → aeróbica de alta intensidade → step (plataforma elevada, anos 1990) → spinning (bike indoor, anos 1990) → Zumba (2001) → HIIT (2010s). Ginástica Aeróbica Esportiva (GAE): modalidade de competição com a BNCC — movimentos de altíssima intensidade e complexidade técnica com música. Brasil é potência na GAE. HIIT (High-Intensity Interval Training): alternância de esforço máximo e recuperação; comprovadamente eficaz para saúde cardiovascular e perda de gordura em tempo reduzido; sessão de 20 min de HIIT equivale a 40-60 min de cardio moderado. Protocolos: Tabata (20s esforço/10s descanso × 8 = 4 min), AMRAP, EMOM. Prática: sessão de HIIT com música — 20 minutos.', ['Quais são as vantagens do HIIT em comparação com o exercício aeróbio contínuo de intensidade moderada? O que a ciência diz sobre a eficácia de cada abordagem?', 'Crie uma sequência de 8 exercícios para um protocolo Tabata de 4 minutos. Explique por que você escolheu cada exercício.']),
  createLesson('g3-ef-b2-l14', 'L14: Esportes de Inverno — Contexto Global e o Brasil', 'educacao_fisica', 'O Brasil não tem neve, mas tem atletas olímpicos de inverno desde 1992. Esportes de inverno olímpicos: esqui alpino, esqui cross-country, biatlo (esqui + tiro), salto de esqui, patinação artística, patinação de velocidade, hóquei no gelo, curling, bobsled, luge, skeleton. Representação brasileira nos Jogos de Inverno: Michael dos Santos (Fórmula 1 precisa brasileira no tobogã/skeleton — Lillehammer 1994); Isadora Williams (patinação artística — única representante por 4 Olimpíadas de Inverno). Esqui aquático e wakeboard no Brasil: adaptação do conceito de "deslizar" para ambientes quentes, praticado nos lagos e represas. O patinação no gelo em cidades quentes: pistasartificiais em shoppings de Palmas, Goiânia, etc. Questão: por que países tropicais participam dos Jogos de Inverno? Motivação, inclusão olímpica ou curiosidade?', ['Por que o Brasil, país tropical, envia atletas aos Jogos Olímpicos de Inverno? O que motiva esses atletas?', 'Quais são os esportes de inverno que têm mais popularidade global e por que eles são fortemente concentrados em países de clima frio?']),
  createLesson('g3-ef-b2-l15', 'L15: Dança Afro-Brasileira — Identidade e Resistência', 'educacao_fisica', 'As danças afro-brasileiras são formas de resistência cultural que sobreviveram à escravidão. Maculelê: dança de origem iorubana praticada com bastões ou facões; ritmo percussivo; originária do Recôncavo Baiano; hoje incorporada à capoeira. Coco de roda: dança do Nordeste com palmas e improviso de versos; patrimônio imaterial do Maranhão, Pernambuco e Alagoas. Jongo: dança do Sudeste de origem banto; os tambus (tambores) e o "ponto" (verso cantado com desafio). Samba de roda do Recôncavo Baiano: patrimônio da UNESCO desde 2005; movimentos sensuais e comunicação não verbal. Lundum: dança mais antiga de origem africana que chegou ao Brasil; antepassada do samba. No Tocantins: congadas e catiras como influências afrodescendentes. Por que essas danças sobreviveram à opressão colonial? O corpo como memória e resistência.', ['Por que as danças afro-brasileiras são consideradas formas de resistência cultural e política além de manifestações artísticas?', 'Escolha uma das danças afro-brasileiras estudadas e pesquise sua origem africana, sua chegada ao Brasil e como ela se transformou ao longo da história.']),
  createLesson('g3-ef-b2-l16', 'L16: Ergonomia e Postura — Vida Contemporânea e Corpo', 'educacao_fisica', 'A vida moderna criou novos problemas posturais. "Text neck" ou "pescoço de texto": flexão cervical contínua pelo uso do celular; cada 15° de inclinação adiciona 10 kg de carga sobre a cervical — a 60° (uso normal do celular) são 27 kg extras. Escoliose: curvatura lateral da coluna; adolescentes são o grupo de maior risco; a EF pode ajudar a detectar precocemente. Hérnia de disco lombar: comum em quem trabalha sentado por muitas horas; prevenção com exercícios de core e postura ao sentar. A pandemia de sedentarismo: trabalho e estudo remotos criaram uma geração com piores índices posturais. Avaliação postural simples: teste de Wall Angel, teste de posição de quadril. Exercícios preventivos: prancha (core), glute bridge, bird-dog, mobilidade torácica (gato-vaca). Aplicação: como organizar a mesa de estudos e o posicionamento do celular.', ['Como o uso excessivo de celular contribui para o problema do "text neck"? Quais são as consequências a longo prazo para a coluna cervical?', 'Quais exercícios simples você pode fazer diariamente para prevenir problemas posturais decorrentes do estudo e uso de tecnologia?']),
  createLesson('g3-ef-b2-l17', 'L17: Simulado de EF — Conteúdos para Vestibulares', 'educacao_fisica', 'Embora EF não seja disciplina específica no ENEM, os conteúdos de saúde, corpo, esporte e cultura corporal aparecem na área de "Linguagens e Códigos e suas Tecnologias". Temas que aparecem: saúde e qualidade de vida, atividade física e doenças crônicas, esporte e sociedade, corpo e mídia, manifestações culturais e corporais, danças, lutas e ginástica como patrimônio cultural. Simulado: questões de vestibulares e ENEM que envolvem conteúdos de EF. Estratégia de resposta: conectar conhecimento de EF com análise sociocultural, histórica e científica. Principais vestibulares que cobram EF: FUVEST, UNICAMP, UFT, UEG. Revisão de conceitos: saúde (OMS), aptidão física, sedentarismo, cultura corporal, esporte como fenômeno social.', ['Quais temas de EF aparecem com mais frequência no ENEM e nos vestibulares? Como você deve abordar essas questões?', 'Resolva as questões do simulado e analise seu desempenho: quais conceitos você precisa revisar antes das provas?']),
  createLesson('g3-ef-b2-l18', 'L18: Revisão do 2º Bimestre — Projeto e Reflexão', 'educacao_fisica', 'Revisão dos conteúdos do 2º bimestre: análise crítica da mídia esportiva, tênis, judô avançado, futebol feminino, longevidade e atividade física, esportes de precisão, nutrição avançada, legislação esportiva, triatlo, projeto comunitário (1ª sessão), psicologia esportiva, handebol, ginástica aeróbica, esportes de inverno, dança afro-brasileira, ergonomia. Status do Projeto Comunitário: cada grupo apresenta brevemente os resultados da 1ª sessão e o planejamento da 2ª (que ocorrerá no 3º bimestre). Avaliação formativa: seminário temático — grupo de 4 alunos escolhe um tema do bimestre e apresenta 10 minutos de análise crítica com exemplos concretos.', ['Qual foi o tema do 2º bimestre que mais te desafiou a pensar criticamente? Explique por quê.', 'Como está o progresso do seu Projeto Comunitário? O que foi aprendido na 1ª sessão que vai mudar a abordagem na 2ª?']),
];

export const efLessonsB3: Lesson[] = [
  createLesson('g3-ef-b3-l1', 'L1: Cultura Corporal do Cerrado e do Tocantins', 'educacao_fisica', 'O Cerrado é o segundo maior bioma do Brasil e o mais biodiverso do mundo em sua categoria. As práticas corporais do Cerrado são moldadas pela paisagem: chapadas, veredas, rios, dunas de areia branca. Pesca artesanal: tradição de ribeirinhos do Tocantins e Araguaia; conhecimento de cardumes, épocas, técnicas de pesca (tarrafa, linha e anzol, caniço) — uma prática corporal que é também modo de vida. Caça e extrativismo sustentável: tradições dos povos do campo e das florestas. Danças indígenas no cerrado: Krahô (Mehin) e Xerente têm práticas corporais rituais ligadas ao ciclo das chuvas, da colheita e da cura. A disputa pelo cerrado: agronegócio vs. povos tradicionais — o corpo que trabalha a terra. Projeto de documentação: registro de práticas corporais tradicionais do Tocantins (entrevistas com familiares, comunidade).', ['Quais práticas corporais da sua família ou comunidade têm raízes na cultura do Cerrado ou de regiões do Tocantins?', 'Por que é importante documentar e estudar as práticas corporais dos povos tradicionais do Tocantins antes que elas se percam?']),
  createLesson('g3-ef-b3-l2', 'L2: Esporte Inclusivo — Design Universal', 'educacao_fisica', 'O design universal no esporte significa criar práticas que sejam acessíveis a pessoas com e sem deficiência, idosos, crianças e adultos. O modelo social da deficiência: a deficiência não está na pessoa, mas nas barreiras que a sociedade cria. Esporte inclusivo na escola: como adaptar regras e espaços para que todos participem? Exemplos: voleibol sentado com cadeiras para todos; basquete em cadeira com todos em cadeiras; esgrima sentado; atletismo com cegueira simulada. A diferença entre integração (todos juntos mas em atividades separadas) e inclusão (todos juntos na mesma atividade com adaptações). Tecnologia assistiva no esporte: próteses de corrida, cadeiras de basquete, handbike. Projeto: adaptar uma modalidade esportiva para inclusão total em sala de aula — criar as regras adaptadas e aplicá-las.', ['Qual é a diferença entre integração e inclusão no esporte? Por que essa distinção é importante?', 'Adapte uma modalidade esportiva (à sua escolha) para que possa ser praticada por pessoas com diferentes tipos de deficiência junto com pessoas sem deficiência. Descreva as adaptações de regras, espaço e equipamentos.']),
  createLesson('g3-ef-b3-l3', 'L3: Execução do Projeto Comunitário — 2ª Sessão', 'educacao_fisica', 'Segunda (e última) sessão de execução do Projeto Comunitário. Os grupos realizam a intervenção com os ajustes planejados após a 1ª sessão. Protocolo de documentação completo: fotos, vídeos, depoimentos dos participantes (escrito ou em vídeo curto), registro de número de participantes e perfil do público. Após a sessão: diário de campo completo — comparação entre 1ª e 2ª sessão; o que melhorou? O que ainda pode ser melhorado? Início da produção do relatório final (apresentação no 4º bimestre). Discussão coletiva: o que aprender sobre a comunidade ao organizar uma atividade física nela? Como as pessoas respondem? Quais barreiras existem para a prática de atividade física no contexto estudado?', ['Como foi a 2ª sessão do projeto em comparação com a 1ª? Quais ajustes funcionaram? O que você ainda mudaria?', 'Quais barreiras para a prática de atividade física você identificou no contexto da comunidade onde realizou o projeto? Como essas barreiras poderiam ser superadas?']),
  createLesson('g3-ef-b3-l4', 'L4: Atletismo — Corridas de Revezamento e Espirito de Equipe', 'educacao_fisica', 'As corridas de revezamento (4x100m e 4x400m) são únicas no atletismo — transformam um esporte individual em coletivo. O 4x100m: a técnica do bastão é decisiva — quase todos os desclassificações olímpicas são por erros de bastão; zona de transmissão de 20m; as técnicas de passagem de bastão (sobreposta e sombra). O Brasil no 4x100m: a seleção masculina ganhou o ouro no Pré-Olímpico de 2024, com destaque para Rodrigo do Nascimento e Erik Cardoso. Táticas: qual posição para qual corredor (o mais lento nunca vai na 2ª perna, a 4ª perna é sempre o mais rápido). O espírito de equipe no atletismo individual: como atletas que competem uns contra os outros durante a temporada se unem no revezamento? Prática: exercício de passagem de bastão com cones — técnica e timing.', ['Por que a passagem do bastão é considerada o fator mais crítico nas corridas de revezamento? Quais são os erros mais comuns?', 'Como a psicologia do trabalho em equipe muda quando atletas que normalmente competem individualmente precisam cooperar em um revezamento?']),
  createLesson('g3-ef-b3-l5', 'L5: Yoga e Mindfulness — Prática Aprofundada', 'educacao_fisica', 'Aprofundamento na prática de yoga e mindfulness. O yoga como sistema completo: Ashtanga (8 membros) de Patanjali — não apenas posturas (asanas) mas ética (yamas e niyamas), pranayama (respiração), pratyahara (retirada dos sentidos), dharana (concentração), dhyana (meditação), samadhi (iluminação). A atenção plena (mindfulness) de Jon Kabat-Zinn: prática secular derivada do budismo; evidências científicas em ansiedade, depressão, dor crônica, performance esportiva. Técnicas avançadas de pranayama: Nadi Shodhana (respiração alternada), Kapalbhati (respiração de fogo), Bhramari (zumbido de abelha). A relação yoga e neurociência: como práticas meditativas remodelariam o cérebro (neuroplasticidade). Prática: sessão completa de 40 minutos de yoga — asanas + pranayama + savasana profundo.', ['Como o Ashtanga yoga de Patanjali vai além das posturas físicas? O que isso revela sobre a concepção indiana de saúde e bem-estar?', 'Quais são as evidências científicas sobre os benefícios da prática regular de mindfulness? Como esses benefícios se aplicam especificamente a estudantes do ENEM?']),
  createLesson('g3-ef-b3-l6', 'L6: Esporte e Política — Boicotes, Manifestações e Poder', 'educacao_fisica', 'O esporte nunca foi apolítico — é arena de poder. Boicotes olímpicos: 1936 (discussão de boicote às Olimpíadas de Hitler — falhou); 1956 (Hungria, Egito e Iraque boicotam por razões políticas); 1976 (26 países africanos boicotam por participação da África do Sul); 1980 (EUA boicotam Moscou — Guerra Fria); 1984 (URSS boicota Los Angeles como retaliação). O esporte como propaganda: Olimpíadas de Berlim 1936 — Leni Riefenstahl e o cinema de propaganda nazista vs. Jesse Owens, o negro americano que ganhou 4 ouros e constrangeu Hitler. A FIFA como poder político: escândalos de corrupção (Joseph Blatter), decisão de sediar Copa no Qatar (2022) — clima, direitos humanos, mortes de trabalhadores migrantes. Protesto de atletas: Colin Kaepernick, Carlos/Smith, manifestações do Black Lives Matter em 2020.', ['Por que alguns afirmam que o esporte "nunca foi apolítico"? Use exemplos históricos para sustentar esse argumento.', 'Como a Copa do Mundo no Qatar em 2022 evidenciou as contradições entre os negócios do futebol global e os direitos humanos?']),
  createLesson('g3-ef-b3-l7', 'L7: Pilates e Treinamento Funcional', 'educacao_fisica', 'O Pilates foi criado por Joseph Pilates (1880-1967), alemão que viveu na Inglaterra e nos EUA. Princípios: centro (core como base de todo movimento), concentração (foco mental), controle (precisão), fluxo (movimento contínuo e suave), precisão e respiração. Equipamentos: reformer (plataforma deslizante), cadeirinha, barril, wall unit. Pilates solo (mat): pode ser feito sem equipamentos; os 34 exercícios originais de "Return to Life". Benefícios comprovados: dor lombar, postura, equilíbrio, consciência corporal, desempenho esportivo. Treinamento Funcional: exercícios que mimetizam movimentos da vida real (puxar, empurrar, agachar, carregar, girar, saltar); TRX (suspension training — peso do corpo como resistência). A diferença entre exercício funcional (agachamento, terra) e exercício de isolamento (leg extension, biceps curl). Prática: circuito funcional de 30 minutos com 8 estações.', ['Quais são os 6 princípios do Pilates e como eles se diferenciam da abordagem do treinamento de musculação convencional?', 'O que caracteriza um exercício funcional? Por que ele é considerado mais benéfico para a saúde do que exercícios de isolamento muscular?']),
  createLesson('g3-ef-b3-l8', 'L8: Surf e Esportes Aquáticos Brasileiros', 'educacao_fisica', 'O Brasil é uma das maiores potências do surf mundial. Italo Ferreira (ouro olímpico em Tóquio 2020), Gabriel Medina (3 vezes campeão mundial da WSL), Tatiana Weston-Webb, Silvana Lima. A técnica do surf: leitura de ondas (como identificar onde a onda vai quebrar), posição no board (stance — regular ou goofy), remada eficiente, take-off (levantar no board), manobras básicas (trim, bottom turn, cutback, re-entry). Modalidades: surf convencional, bodyboard (deitado), longboard (pranchas longas e estilo clássico), stand-up paddle (SUP). Surf no Tocantins: sem mar, mas o Rio Tocantins e o Araguaia têm praias de água doce (julho-outubro) onde o SUP é praticado. Kitesurf: kite + prancha; o Parque das Aves em Palmas tem potencial para essa prática. Wakeboard: reboque por barco ou cabo fixo.', ['Por que o Brasil é tão dominante no surf mundial? Quais fatores naturais e culturais explicam essa supremacia?', 'Quais esportes aquáticos são praticáveis nos rios do Tocantins? O que é necessário em termos de equipamentos e segurança?']),
  createLesson('g3-ef-b3-l9', 'L9: Avaliação Física 2 — Progresso no Meio do Segundo Semestre', 'educacao_fisica', 'Segunda avaliação física do ano (1ª foi no início do 1º bimestre). Repetição da bateria completa: Cooper, flexão de braço, abdominal, sentar-e-alcançar, sprint 40m, salto vertical. Análise de progresso individual: quanto cada aluno melhorou em cada capacidade? Qual foi a trajetória? Análise por grupo: quais capacidades melhoraram mais na turma? Quais não progrediram? Por quê? Discussão: qual é a relação entre as mudanças na aptidão física e os hábitos relatados pelos alunos (sono, alimentação, prática esportiva extracurricular)? Meta para a avaliação final: quais ajustes serão feitos na rotina para atingir as metas estabelecidas no 1º bimestre?', ['Comparando as 2 avaliações físicas do ano, qual foi sua principal melhoria? O que você fez de diferente que explica esse progresso?', 'Em qual capacidade você teve menor progresso? Quais mudanças de hábito você pretende fazer até a avaliação final?']),
  createLesson('g3-ef-b3-l10', 'L10: Esportes Adaptados — Aula Experimental', 'educacao_fisica', 'Aula experimental de esportes paralímpicos e adaptados. Rotações de 15 minutos em 4 estações: (1) Goalball — esporte para cegos, todos vendados; bola com guizos; gol marcado se a bola cruzar a linha; defesa com o corpo inteiro no chão. (2) Basquete em cadeira de rodas — todos em cadeiras; as regras são similares ao basquete convencional, com adaptações (2 impulsos antes de quicar). (3) Atletismo adaptado — corrida com parceiro guia (um aluno é "guiado" de olhos fechados pelo outro). (4) Boccia — esporte de precisão; lançar bolas coloridas o mais próximo possível de uma bola branca (jack). Após as rotações: discussão em roda — o que você sentiu em cada esporte? O que essa experiência revela sobre o que é "deficiência"?', ['O que a experiência de jogar goalball vendado revelou sobre como atletas com deficiência visual percebem o espaço e o jogo?', 'Após as experimentações, como mudou sua percepção sobre o que significa ter uma deficiência? O que surpreendeu você?']),
  createLesson('g3-ef-b3-l11', 'L11: Futebol de Salão — Futsal Nacional e Internacional', 'educacao_fisica', 'O futsal foi criado no Brasil — na YMCA de Montevidéu, Uruguai, por Juan Carlos Ceriani em 1930, adaptação para uso interno em dias de chuva. Depois se desenvolveu no Brasil a ponto de ser considerado a "escola" do futebol brasileiro: Ronaldo, Ronaldinho, Neymar — todos jogaram futsal na infância. A AMF (Associação Mundial de Futsal) vs. a FIFA Futsal: duas entidades, duas regras ligeiramente diferentes. Brasil na FIFA Futsal: 5 títulos mundiais (1989, 1992, 1996, 2004, 2008). Falcão: considerado o maior de todos os tempos. Copa do Mundo de Futsal 2024: Brasil vs. Argentina na final — o eterno clássico sul-americano. Futsal nas escolas: a importância da quadra de futsal para a EF escolar brasileira. Tática avançada: o pressing alto e a marcação pressão no futsal.', ['Por que o futsal é considerado fundamental para a formação técnica dos jogadores brasileiros de futebol?', 'Explique o que é o pressing alto no futsal e por que essa tática cria vantagem táticas para equipes bem condicionadas fisicamente.']),
  createLesson('g3-ef-b3-l12', 'L12: Caminhada e Trekking — A Prática mais Democrática', 'educacao_fisica', 'A caminhada é o exercício mais democrático do mundo — sem equipamentos especiais, sem custo, para todas as idades. OMS: 150-300 min/semana de caminhada moderada são suficientes para atingir os benefícios à saúde. The Danish concept of "Hygge" e a caminhada na natureza: culturas nórdicas integram caminhada ao ar livre como prática social e de bem-estar. Trekking: caminhada em trilhas naturais, com planejamento e equipamentos. Trilhas do Tocantins: Trilha do Rio Sono (Mateiros, região do Jalapão — 200 km), Trilha do Cerrado, trilhas em Taquaruçu, Natividade. Orientação em trilhas: bússola, mapa topográfico, GPS. Mochila de trekking: peso ideal (10-15% do peso corporal), distribuição de carga, itens essenciais. Trekking e sustentabilidade: como trilheiros responsáveis preservam o ambiente. Prática: caminhada com mapa simples no entorno da escola.', ['Por que a caminhada é considerada o exercício mais democrático e sustentável de todos? O que a torna ideal para todas as populações?', 'Descreva uma trilha de trekking do Tocantins que você conhece ou gostaria de conhecer. Quais são os desafios e atrativos dessa trilha?']),
  createLesson('g3-ef-b3-l13', 'L13: Esporte e Racismo — Análise Profunda', 'educacao_fisica', 'O racismo no esporte é um reflexo do racismo na sociedade. História: a exclusão formal de atletas negros em ligas americanas (baseball — Jackie Robinson quebrou a barreira em 1947); a exclusão da África do Sul do esporte internacional por causa do apartheid (1964-1992). No Brasil: o futebol como espaço contraditório — ao mesmo tempo democrático e racista; cânticos racistas nos estádios; racismo contra Vinícius Jr. no futebol espanhol (2023) gerou crise diplomática. A Super-representação e a exploração: por que negros são maioria nos esportes mais lucrativos (futebol, basquete, atletismo) mas minoria nas posições de liderança (técnicos, diretores, presidentes de clubes)? O fenômeno da "stacking" (empilhamento): atletas negros são direcionados para certas posições baseado em estereótipos raciais. Resistência: como atletas negros usam o esporte como plataforma política.', ['O que é o fenômeno de "stacking" no esporte? Como ele reflete estereótipos raciais que limitam atletas negros?', 'Como a carreira de Vinícius Jr. e as respostas ao racismo que ele sofreu evidenciam tanto o progresso quanto as limitações do combate ao racismo no futebol europeu?']),
  createLesson('g3-ef-b3-l14', 'L14: Preparação para a Vida Ativa — Hábitos Duradouros', 'educacao_fisica', 'Como criar hábitos de atividade física que durem para além do Ensino Médio? A ciência dos hábitos (Charles Duhigg — "O Poder do Hábito"): rotina de gatilho → rotina → recompensa. O "habit stacking" (empilhamento de hábitos — James Clear — "Hábitos Atômicos"): associar novos hábitos a hábitos existentes. Os "small wins" (pequenas vitórias): começar pelo mais fácil e construir momentum. Barreiras para a atividade física na vida adulta: trabalho, família, cansaço, custo, falta de tempo (o obstáculo mais citado, mas 30 min de caminhada cabe em qualquer dia). O ambiente como fator: deixar a roupa de treino separada, ter uma academia no trajeto, ter amigos que treinam. A tribo importa: pessoas ativas tendem a se rodear de pessoas ativas. Identificando sua atividade ideal: a que você faz com prazer quando ninguém te obriga.', ['Segundo a ciência dos hábitos, quais são os passos para criar e manter um hábito de atividade física? Como você pode aplicar isso na sua vida?', 'Qual é a única atividade física que você faria mesmo sem obrigação? Como você pode estruturar seu ambiente para facilitar essa prática?']),
  createLesson('g3-ef-b3-l15', 'L15: Ginástica — Rebeca Andrade e o Brasil', 'educacao_fisica', 'Rebeca Andrade é a maior ginasta da história do Brasil e símbolo de uma geração. Trajetória: nascida em Guarulhos (SP), periférica, sofrendo 5 cirurgias no joelho ao longo da carreira; 2 ouros olímpicos em Paris 2024 (solo e individual geral), 4 medalhas olímpicas totais — nenhum brasileiro havia ganho mais. O que torna Rebeca especial: técnica excepcional + carisma + diversidade corporal (representa um novo padrão na ginástica). Artístico vs. físico: a ginástica exige ambos; o sistema de pontuação premia dificuldade (nota D) e execução (nota E). Rebeca e a representatividade: a primeira brasileira negra a ganhar ouro olímpico em ginástica; o impacto nas meninas negras das periferias que se identificam com ela. Prática: sequência de solo — rolamento, parada de mão (bananeira), rodante — com segurança.', ['Por que a trajetória de Rebeca Andrade é considerada inspiradora além do esporte? Qual é o seu impacto social e de representatividade?', 'O sistema de pontuação da ginástica artística (nota D + nota E) cria um dilema: fazer movimentos mais difíceis mas com mais erros, ou movimentos mais simples com execução perfeita. Qual você escolheria? Justifique.']),
  createLesson('g3-ef-b3-l16', 'L16: Esportes do Futuro — Inovações e Tendências', 'educacao_fisica', 'O esporte do futuro está sendo construído agora. Tendências: (1) E-sports como esporte olímpico (discussão para LA 2028 e Paris 2032); (2) Enhanced Olympics — atualização constante de regras para aumentar espetáculo; (3) Esportes de mobilidade elétrica (patins elétricos, monopatin, e-bike como modalidades); (4) AI coaching — treinadores de inteligência artificial que analisam biomecânica em tempo real; (5) Neuroesporte — interfaces cérebro-computador que permitiriam controle de próteses ou exoesqueletos; (6) VR/AR no esporte — treinamento imersivo em realidade virtual. O Metaverso e o esporte: competições em mundos virtuais? Nike, Adidas e Under Armour já vendem equipamentos para avatares. A corrida tecnológica e a igualdade de acesso: novas tecnologias esportivas ampliam ou reduzem a desigualdade?', ['Quais das tendências do esporte do futuro você considera mais promissoras? Quais apresentam mais riscos?', 'As novas tecnologias esportivas (IA, VR, wearables avançados) têm o potencial de ampliar a desigualdade no esporte? Justifique sua resposta.']),
  createLesson('g3-ef-b3-l17', 'L17: Preparação da Apresentação do Projeto Comunitário', 'educacao_fisica', 'Preparação da apresentação final do Projeto Comunitário de EF. Estrutura da apresentação (15-20 min por grupo): (1) Diagnóstico: quem é o público? Qual era a necessidade identificada? (2) Planejamento: o que foi proposto? Por quê? (3) Execução: como foram as 2 sessões? Desafios e soluções; (4) Resultados: número de participantes, depoimentos, fotos/vídeos; (5) Avaliação: o que funcionou? O que não funcionou? O que repetiriam? O que mudariam? (6) Aprendizados: o que a experiência ensinou sobre comunidade, prática corporal, planejamento? Ensaio da apresentação em sala com feedback dos colegas. Rubrica de avaliação: diagnóstico (20%), planejamento (20%), execução (30%), avaliação crítica (20%), apresentação (10%).', ['Ao preparar a apresentação do projeto, quais foram os aprendizados mais significativos — sobre a comunidade, sobre si mesmo e sobre prática corporal?', 'Que conselho você daria para alunos que forem fazer o mesmo projeto no próximo ano? O que você faria diferente desde o início?']),
  createLesson('g3-ef-b3-l18', 'L18: Revisão do 3º Bimestre — Integração e Síntese', 'educacao_fisica', 'Revisão e síntese do 3º bimestre: cultura corporal do Cerrado, esporte inclusivo, projeto comunitário (2ª sessão), atletismo de revezamento, yoga aprofundado, esporte e política, pilates e funcional, surf e esportes aquáticos, avaliação física 2, esportes adaptados (experimental), futsal, caminhada e trekking, racismo no esporte, hábitos duradouros, Rebeca Andrade, esportes do futuro, preparação do projeto. Avaliação integradora: seminário temático em duplas — escolher 2 temas do bimestre e apresentar como eles se conectam (ex: esporte e racismo + hábitos duradouros; esporte inclusivo + esportes do futuro). O objetivo é demonstrar síntese e conexão entre temas, não apenas recitação de conteúdo.', ['Quais 2 temas do 3º bimestre você escolheu para o seminário? Qual é a conexão que você identifica entre eles?', 'Como você descreve seu crescimento ao longo deste ano de EF? O que mudou na sua relação com as práticas corporais?']),
];

export const efLessonsB4: Lesson[] = [
  createLesson('g3-ef-b4-l1', 'L1: Apresentação do Projeto Comunitário — Grupo 1', 'educacao_fisica', 'Início das apresentações do Projeto Comunitário de EF da 3ª Série. Cada grupo tem 15-20 minutos para apresentar: diagnóstico da comunidade, planejamento, execução das 2 sessões, resultados (participantes, depoimentos, fotos/vídeos) e avaliação crítica do processo. Após cada apresentação: 5 minutos de perguntas da turma e do professor. Critérios de avaliação (rubrica): profundidade do diagnóstico (20%), coerência do planejamento (20%), qualidade da execução (30%), análise crítica dos resultados (20%), comunicação oral (10%). Os projetos são o ápice da jornada de EF na escola — conectam teoria, prática e realidade social.', ['O que diferenciou o seu projeto de uma "aula de EF comum"? O que fazer com uma comunidade real ensina que uma aula na escola não ensina?', 'Após assistir às apresentações dos colegas, quais projetos te inspiraram? O que você teria feito diferente em cada um deles?']),
  createLesson('g3-ef-b4-l2', 'L2: Apresentação do Projeto Comunitário — Grupo 2', 'educacao_fisica', 'Continuação das apresentações dos Projetos Comunitários. Cada grupo apresenta sua intervenção, com ênfase nos resultados alcançados e nos aprendizados do processo. Análise comparativa: quais contextos foram escolhidos? (idosos, crianças, bairro específico, escola parceira, praça pública?) Quais práticas corporais foram utilizadas? Quais dificuldades foram mais comuns entre os grupos? Como as soluções encontradas se relacionam com os conceitos estudados ao longo do ano? Construção coletiva: ao final de todas as apresentações, a turma produz um "Mapa de Práticas Corporais Comunitárias do Tocantins" com os locais e públicos atendidos pelos projetos.', ['O que o conjunto de projetos apresentados revela sobre as necessidades de prática corporal na comunidade de Palmas e arredores?', 'Se você pudesse continuar o projeto por mais 6 meses, o que faria diferente e por quê?']),
  createLesson('g3-ef-b4-l3', 'L3: Avaliação Física Final — Comparativo do Ano', 'educacao_fisica', 'Avaliação física final do ano — completando o ciclo de 3 medições (início do 1º bimestre, meio do 3º bimestre, agora). Bateria completa repetida: Cooper, flexão de braço, abdominal, sentar-e-alcançar, sprint 40m, salto vertical. Análise longitudinal completa: cada aluno vê sua evolução ao longo de todo o ano. Análise da turma: quais capacidades mais melhoraram? Quais menos? O que explica as diferenças? Celebração dos progressos: reconhecimento público dos maiores desenvolvimentos (não dos melhores valores brutos — mas dos maiores saltos de melhoria). Reflexão: a melhora de aptidão física ao longo do ano reflete mudanças de hábito? O que vai mudar na vida adulta para manter esse nível?', ['Comparando as 3 avaliações físicas do ano, qual foi a sua maior evolução? O que você fez de diferente que explica esse resultado?', 'Você atingiu as metas que estabeleceu no início do ano? O que aprendeu sobre estabelecimento de metas realistas e motivação intrínseca?']),
  createLesson('g3-ef-b4-l4', 'L4: EF e o Projeto de Vida — Além da Escola', 'educacao_fisica', 'A Educação Física escolar é apenas o começo. A vida adulta oferece um mundo de práticas corporais: academia, corrida de rua, ciclismo, natação, yoga, danças, esportes coletivos em ligas amadores, trilhas, surfe, artes marciais, meditação. O desafio: como manter práticas corporais quando não há "horário de EF"? Pesquisa: 80% dos adultos que praticavam esporte na escola param nos primeiros 2 anos da vida adulta. O que mantém os 20% ativos? Identificação de valores: quem pratica por saúde tem mais consistência que quem pratica por estética. Projetos de vida e atividade física: a universidade, o trabalho, a família e os esportes — como conciliar? Identificação de recursos na cidade onde você vai viver: onde praticar esporte em Palmas? Em outras cidades do Tocantins? Em capitais de estado (se for para a faculdade)?', ['Qual é o seu projeto de vida ativa para os próximos 5 anos? Quais práticas corporais você pretende manter e em quais contextos (cidade, tempo, com quem)?', 'O que você vai fazer nos primeiros 3 meses após sair da escola para garantir que não entre na estatística dos 80% que param de praticar esporte?']),
  createLesson('g3-ef-b4-l5', 'L5: Esporte e Arte — Crossover', 'educacao_fisica', 'O esporte e a arte dialogam cada vez mais. Exemplos: (1) A ginástica artística onde o esportivo e o estético são indissociáveis; (2) O breakdance/breaking, que foi esporte olímpico em Paris 2024; (3) O parkour como forma de dança urbana; (4) O futebol artístico (freestyle football — malabarismo com bola); (5) A natação artística (sincronizada). Esportistas que viraram artistas: Muhammad Ali como poeta e performer; Dennis Rodman como personagem artístico; Neymar como símbolo de estilo além do futebol. O conceito de "jogabilidade": qualidade estética do jogo — por que dizemos que um jogador tem "bom futebol"? Arte que representa o esporte: Pelé retratado por Andy Warhol; corridas de Fórmula 1 viram tema de Banksy; O futebol de Jorge Amado. Projeto: criar uma expressão artística (desenho, texto, vídeo) sobre uma prática corporal que você ama.', ['Em que momentos o esporte se torna arte? Quais são os critérios que separam uma performance esportiva excepcional de uma obra de arte?', 'Crie uma expressão artística (à sua escolha: desenho, poema, vídeo curto, colagem) sobre uma prática corporal que tenha significado especial para você.']),
  createLesson('g3-ef-b4-l6', 'L6: Esporte e Sustentabilidade — Responsabilidade Ambiental', 'educacao_fisica', 'O esporte é grande consumidor de recursos naturais. Grandes eventos: Copa do Mundo no Qatar usou 1,4 milhão de toneladas de CO2 para construção de estádios; a neve artificial nos Jogos de Inverno consome enormes volumes de água e energia. Os Jogos Olímpicos de Paris 2024 foram os primeiros com meta de carbono neutro (atingiram 50% de redução vs. 2012). Marcas esportivas e sustentabilidade: Adidas × Parley (produtos feitos de plástico do oceano), Nike × Grind (solas feitas de tênis reciclados), Patagonia (doação de 1% do faturamento para o meio ambiente). Esportes de natureza e conservação: surfistas são ativistas climáticos (Surfrider Foundation); corredores de trilha demandam preservação dos parques; escaladores lutam contra o desenvolvimento em regiões de montanha. Nossa responsabilidade como praticantes: consumo consciente de equipamentos, transporte até o local de treino, respeito ao ambiente natural.', ['Como grandes eventos esportivos como as Olimpíadas e a Copa do Mundo impactam o meio ambiente? O que já está sendo feito para reduzir esses impactos?', 'Você já fez escolhas de consumo (de equipamentos, roupas esportivas) considerando o impacto ambiental? O que poderia mudar nos seus hábitos?']),
  createLesson('g3-ef-b4-l7', 'L7: Meditação e Saúde Mental — Práticas Finais', 'educacao_fisica', 'Aula de meditação e cuidado com a saúde mental como encerramento da jornada de EF. A meditação mindfulness: baseada na atenção plena ao momento presente; 10 min/dia de prática reduzem ansiedade em 30% (meta-análise de 200 estudos). Técnicas praticadas: body scan (varredura corporal — identificar tensões), meditação de bondade amorosa (metta — cultivar compaixão por si mesmo e pelos outros), visualização de lugar seguro. A autocompaixão (Kristin Neff): tratar a si mesmo com a mesma gentileza que você trata um amigo — antídoto ao autocrítica excessiva que afeta muitos estudantes antes do ENEM. A gratidão como prática: escrever 3 gratidões diárias reduz sintomas depressivos. A relação entre práticas corporais e saúde mental ao longo da vida. Prática: meditação guiada de 25 minutos.', ['Como a meditação e a autocompaixão podem ajudar estudantes a lidar com a pressão do ENEM e com as transições para a vida adulta?', 'Quais técnicas de atenção plena você praticou neste ano? Quais funcionaram melhor para você? Como pretende continuar essas práticas?']),
  createLesson('g3-ef-b4-l8', 'L8: Olimpíadas e Paraolimpíadas — Legado e Impacto', 'educacao_fisica', 'O legado olímpico vai além das medalhas. Legado material: infraestrutura esportiva, Vila Olímpica, transporte (metro do Rio, construído para 2016). Legado imaterial: inspiração de jovens, visibilidade de modalidades, aumento de praticantes nas modalidades olímpicas. O caso de Paris 2024: legado sustentável — 95% dos esportes em instalações existentes; a cerimônia no Sena como declaração de ambição ecológica; uso de ônibus elétricos para transporte dos atletas. Paraolimpíadas e mudança cultural: o Movimento Paralímpico mudou a percepção global sobre a deficiência — de tragédia para capacidade. No Brasil: o legado do Rio 2016 — o que ficou? (Copa do Mundo 2014 e Olimpíadas 2016 deixaram dívidas municipais mas também instalações e visibilidade). Tocantins no legado: o esporte escolar como herança olímpica local.', ['O que é o "legado olímpico" e por que ele é frequentemente questionado pelos moradores das cidades-sede? O Rio 2016 deixou um legado positivo?', 'Como as Paralimpíadas transformaram a percepção global sobre a deficiência? Qual impacto concreto isso teve nas políticas de inclusão?']),
  createLesson('g3-ef-b4-l9', 'L9: Portfólio Final de EF — Reflexão e Síntese', 'educacao_fisica', 'Construção do portfólio final de EF da 3ª Série. O portfólio documenta a jornada de 3 anos de EF no Ensino Médio. Componentes: (1) Linha do tempo de práticas corporais: da 1ª Série até hoje — quais práticas foram experimentadas? Quais ficaram? (2) As 3 avaliações físicas do ano: progresso e análise; (3) Reflexão sobre o projeto comunitário: o que aprendi sobre a comunidade e sobre mim mesmo? (4) Análise de um tema de EF que mudou minha visão: qual foi? Por quê? (5) Meu projeto de vida ativa: quais práticas corporais vou manter e como? (6) Uma mensagem para mim mesmo, para ser lida em 2031. O portfólio é entregue ao professor e devolvido na formatura.', ['Ao construir a linha do tempo de práticas corporais dos últimos 3 anos, quais transformações você percebe em si mesmo como praticante?', 'Escreva a mensagem para ser incluída no seu portfólio: o que você quer que o "eu" de 5 anos saiba sobre quem você é hoje, suas conquistas e seus sonhos de vida ativa?']),
  createLesson('g3-ef-b4-l10', 'L10: Esporte como Expressão da Identidade', 'educacao_fisica', 'Como o esporte constrói e expressa identidades individuais e coletivas? Identidade esportiva: ser "corredor", ser "yogi", ser "jogador de futebol" — como essas identidades moldam comportamentos e escolhas. A torcida como comunidade de pertencimento: o ritual de ir ao estádio (ou assistir pela TV), o uniforme como símbolo de filiação, o sofrimento e a alegria coletivos. A identidade nacional e o esporte: o Brasil = futebol? Ou estamos além disso? (vôlei, judô, ginástica...). Esporte e masculinidade: como os esportes coletivos constroem modelos de masculinidade — e como isso pode ser transformado. Esporte e feminidade: como mulheres que praticam esportes de contato são julgadas diferentemente de homens. Identidade trans no esporte: o debate sobre mulheres trans em categorias femininas. Como o esporte pode ser espaço de libertação identitária?', ['De que forma(s) o esporte faz parte da sua identidade? Como a prática corporal moldou quem você é?', 'Como você vê o debate sobre identidade trans no esporte? Quais princípios deveriam guiar as políticas das federações esportivas?']),
  createLesson('g3-ef-b4-l11', 'L11: Basquete de Rua — Street Basketball e Cultura Urbana', 'educacao_fisica', 'O basquete de rua é berço de inovação e expressão cultural. O AND1 Mixtape Tour (anos 2000): basquete de rua americano com dribles impossíveis, virou cultura global. O 3x3 basquete olímpico (desde Tóquio 2021): formato mais urbano, menor quadra, regras aceleradas. Streetball no Brasil: a quadra de São Paulo onde nasceu o basquete das periferias. O Rucker Park em Harlem (Nova York): lendária quadra onde stars da NBA jogaram lado a lado com jogadores de rua. A cultura do basquete: música (hip-hop e basquete têm raízes comuns), moda (tênis de basquete como moda urbana global), gírias, identidade de bairro. Projeto: torneio de 3x3 da turma — regras simplificadas, arbitragem pelos próprios alunos, espírito de streetball (jogo criativo, não violento).', ['Por que o basquete de rua e o 3x3 têm uma cultura própria diferente do basquete de quadra? O que eles representam para as comunidades periféricas?', 'Como o hip-hop e o basquete de rua se desenvolveram juntos como formas de expressão das comunidades negras periféricas nos EUA? Quais paralelos existem no Brasil?']),
  createLesson('g3-ef-b4-l12', 'L12: EF na Universidade e Após — Recursos e Oportunidades', 'educacao_fisica', 'A vida universitária apresenta oportunidades e desafios para a prática esportiva. Esporte universitário no Brasil: Associações Atléticas (cada universidade tem a sua); Jogos Universitários Brasileiros (JUB); FISU (Federação Internacional de Esporte Universitário — Universíadas). UFT (Universidade Federal do Tocantins): tem programas de esporte e lazer, academia aberta à comunidade, grupos de corrida. Bolsas esportivas: algumas universidades (especialmente as americanas) oferecem bolsas completas para atletas de alto nível — pesquisar as exigências. Esporte para além da universidade: clubes esportivos, ligas amadoras, corridas de rua, grupos de caminhada. Como usar apps para encontrar grupos: Strava (corrida/ciclismo), Gympass (academias), Meetup (grupos de esportes). Cidades universitárias: como manter vida ativa longe de casa?', ['Como você planeja manter a prática esportiva durante a vida universitária? Quais recursos da universidade para onde você pretende ir você já pesquisou?', 'Se tivesse que montar um grupo esportivo informal na sua cidade, qual esporte escolheria? Por quê? Como você o organizaria?']),
  createLesson('g3-ef-b4-l13', 'L13: EF e Cidadania — Corpo no Espaço Público', 'educacao_fisica', 'O espaço público é o espaço do corpo. A cidade como palco para as práticas corporais: calçadas e ciclovias como infraestrutura de saúde pública. A disputa pelo espaço público: carros vs. pedestres e ciclistas; favela e falta de parques; privatização de praias. Políticas públicas de atividade física: Academia da Saúde (SUS), Virada Esportiva (SP), programas de corrida municipais. Participação cidadã no esporte: como cobrar melhor infraestrutura esportiva do poder público? Petições, audiências públicas, pressão organizada. O Parque Cesamar e a Orla de Palmas: exemplos de espaço público para práticas corporais — como preservá-los e expandi-los? O direito ao lazer é garantido pela Constituição (art. 6º) — como exigi-lo? Projeto de cidadania: carta ao prefeito de Palmas pedindo melhoria em um espaço esportivo específico.', ['Como o direito ao lazer e à prática esportiva, garantido pela Constituição, está sendo cumprido (ou não) na sua cidade?', 'Escreva uma carta ao prefeito de Palmas (ou da sua cidade) identificando um problema de infraestrutura esportiva e propondo uma solução concreta.']),
  createLesson('g3-ef-b4-l14', 'L14: Atividade Livre — Esporte que Você Ama', 'educacao_fisica', 'Penúltima aula de EF do Ensino Médio — aula especial de prática livre. Cada aluno lidera uma atividade de 10 minutos para a turma: uma prática corporal que aprendeu fora da escola, um jogo da infância, uma dança, um movimento meditativo, um esporte que descobriu ao longo do Ensino Médio. Regra: a atividade deve ser inclusiva (todos podem participar) e segura. Após cada prática: 2 min de reflexão — por que essa prática importa para você? O que ela diz sobre quem você é? Objetivo: celebrar a diversidade de corpos, gostos e histórias da turma e reconhecer que cada prática corporal tem igual valor — do xadrez ao futebol, da meditação ao breaking.', ['Qual prática corporal você escolheu para compartilhar com a turma? O que ela significa para você e o que você quer que os colegas experienciem?', 'Após participar das atividades de todos os colegas, qual você experimentou pela primeira vez? Gostou? O que isso diz sobre o valor de ser apresentado a novas práticas?']),
  createLesson('g3-ef-b4-l15', 'L15: Encerramento — Carta ao Corpo e Gratidão', 'educacao_fisica', 'A última aula de Educação Física do Ensino Médio. Atividade principal: "Carta ao Corpo" — cada aluno escreve uma carta para o próprio corpo, refletindo sobre toda a jornada de 3 anos. A carta deve contemplar: (1) Agradecimento — pelo que o corpo foi capaz de fazer, pelas práticas que proporcionou; (2) Reconhecimento — dos desafios, das limitações, das superações; (3) Promessa — o que você vai fazer por esse corpo daqui em diante; (4) Desejo — o que você quer viver com esse corpo nos próximos anos. Leitura voluntária em roda. Após as leituras: o professor compartilha uma última mensagem — sobre como o corpo é o lar de toda experiência humana, e cuidar dele é um ato de amor próprio e de responsabilidade. Parabéns, atletas da vida.', ['Qual foi a mais importante coisa que você aprendeu sobre o seu corpo e sobre as práticas corporais ao longo deste 3 anos de EF no Ensino Médio?', 'Leia a carta que você escreveu para o seu corpo em voz alta (se quiser). O que você prometeu? Você vai cumprir?']),
  createLesson('g3-ef-b4-l16', 'L16: Avaliação Final e Portfólio — Entrega', 'educacao_fisica', 'Entrega e avaliação final do portfólio de EF da 3ª Série. O professor avalia: profundidade das reflexões, honestidade, conexão com os temas estudados, qualidade da análise sobre o projeto comunitário, clareza do projeto de vida ativa. Avaliação prática: demonstração individual de uma habilidade motora escolhida pelo aluno (fundamento esportivo, sequência de ginástica, sequência de dança, etc.) — 2-3 min. Autoavaliação: cada aluno atribui notas a si mesmo em 4 dimensões: participação ativa, aprendizado teórico, desenvolvimento físico, desenvolvimento pessoal. O professor e o aluno discutem as diferenças entre autoavaliação e avaliação docente. Essa conversa final é o ato mais formativo de toda a disciplina.', ['Ao comparar sua autoavaliação com a avaliação do professor, quais diferenças você percebe? O que elas revelam sobre sua autopercepção?', 'Que nota final você daria para si mesmo neste ano de EF, considerando não apenas a performance física, mas o engajamento, o aprendizado e o crescimento pessoal?']),
  createLesson('g3-ef-b4-l17', 'L17: Celebração Final — Mostra de Práticas Corporais', 'educacao_fisica', 'Celebração final: Mostra de Práticas Corporais da 3ª Série. Evento aberto para outras turmas e familiares. A 3ª Série apresenta o que aprendeu ao longo de 3 anos: cada grupo monta uma estação com uma prática corporal diferente. Estações sugeridas: capoeira, yoga, dança folclórica tocantinense, atletismo (corrida), ginástica, esporte adaptado, corrida de orientação, prática indígena (corrida de tora simbólica). Mensagem da Mostra: as práticas corporais são patrimônio cultural, expressão de identidade e ferramenta de saúde — e todos têm o direito e a capacidade de praticá-las. Encerramento: foto coletiva da turma. Agradecimentos mútuos. O professor entrega a cada aluno um cartão com uma palavra que resume sua jornada na EF.', ['O que a Mostra de Práticas Corporais representou para você? O que você sentiu ao apresentar o que sabe para outras pessoas?', 'Se você pudesse resumir em uma palavra sua jornada de 3 anos na Educação Física, qual seria essa palavra? Justifique.']),
  createLesson('g3-ef-b4-l18', 'L18: Última Aula — O Corpo na Vida que Começa', 'educacao_fisica', 'A última aula da Educação Física do Ensino Médio é uma homenagem ao início. Roda de conversa: cada aluno compartilha como era sua relação com o corpo e com o esporte no início do Ensino Médio, e como ela é agora. O professor apresenta a pesquisa: estudantes que tiveram EF significativa no Ensino Médio têm 2x mais chance de manter hábitos ativos na vida adulta. A vida que começa depois da escola: o mundo adulto com seus desafios e possibilidades. O corpo como aliado: não importa qual carreira você escolha — médico, professor, agricultor, artista, engenheiro — você vai precisar do seu corpo funcionando bem. Cuide dele como um instrumento precioso. A EF termina, o movimento continua. Boa sorte, e — acima de tudo — continuem em movimento.', ['Como você descreve a transformação na sua relação com o corpo e as práticas corporais ao longo dos 3 anos de Ensino Médio?', 'Escreva uma última reflexão: o que você leva da Educação Física para a vida que está começando? Como o movimento vai fazer parte da pessoa que você está se tornando?']),
];
